import axios from 'axios'
import { ElMessage } from 'element-plus'
import router from '@/router'
import { STORAGE_KEYS, RATE_LIMIT } from '@/constants'
import store from '@/store'

// 创建 axios 实例
const request = axios.create({
  baseURL: process.env.VUE_APP_API_BASE_URL,
  timeout: 15000
})

// 请求拦截器
request.interceptors.request.use(
  config => {
    const token = store.state.token || localStorage.getItem(STORAGE_KEYS.TOKEN)
    if (token) {
      config.headers.Authorization = `Bearer ${token}`
    }
    return config
  },
  error => {
    console.error('请求错误:', error)
    return Promise.reject(error)
  }
)

// 响应拦截器
request.interceptors.response.use(
  response => response,
  async error => {
    const originalRequest = error.config

    // 处理限速错误
    if (error.response?.status === 429) {
      const retryAfter = error.response.headers[RATE_LIMIT.RETRY_AFTER] || RATE_LIMIT.DEFAULT_WAIT
      const waitTime = parseInt(retryAfter, 10)

      // 显示友好的中文提示信息
      const minutes = Math.ceil(waitTime / 60)
      ElMessage.warning(`操作过于频繁，请在 ${minutes} 分钟后重试`)

      // 返回一个不带错误信息的对象
      const rateLimitError = new Error()
      rateLimitError.isRateLimit = true
      rateLimitError.retryAfter = waitTime
      return Promise.reject(rateLimitError)
    }

    if (error.response?.status === 401 && !originalRequest._retry) {
      originalRequest._retry = true

      try {
        // 使用 store action 来刷新 token
        const success = await store.dispatch('refreshToken')
        if (success) {
          // 更新原请求的 token
          originalRequest.headers.Authorization = `Bearer ${store.state.token}`
          // 重试原请求
          return request(originalRequest)
        }
      } catch (refreshError) {
        console.warn('Token refresh failed:', refreshError)
        // 刷新失败时，清除登录状态并跳转到登录页
        await store.dispatch('logout')
        router.push('/login')
      }
    }

    return Promise.reject(error)
  }
)

export default request
